INSERT INTO `content_block_values` (`block_id`,`lang`,`value`) VALUES
(1,'en','November 25, 2026 — Dushanbe'),
(2,'en','International Coal Industry Forum'),
(3,'en','Tajikistan 2026'),
(4,'en','Shaping the future of Central Asian coal: growth, innovation and sustainable development'),
(5,'en','Register Now'),
(6,'en','About the Forum'),
(7,'en','<p>The first-ever International Coal Industry Forum in Tajikistan brings together industry leaders, government officials, investors and experts from across Central Asia and beyond. The forum is organized by the Ministry of Industry and New Technologies of the Republic of Tajikistan.</p>'),
(8,'en','<p>The event showcases Tajikistan''s coal industry potential, fosters international cooperation, and presents modern approaches to mining, environmental sustainability, and investment opportunities.</p>'),
(9,'en','Key Topics'),
(10,'en','Six major directions shaping the future of coal in Central Asia'),
(11,'en','Partners & Sponsors'),
(12,'en','Organizations supporting the development of the coal industry'),
(17,'en','<p>The International Coal Industry Forum Tajikistan 2026 is a landmark event dedicated to the development and modernization of the coal industry in the Republic of Tajikistan and Central Asia as a whole.</p>'),
(18,'en','<p>For the first time, Tajikistan brings together leading experts, government officials, investors, mining companies, and international organizations to discuss the current state and future prospects of the coal industry in the region.</p>'),
(19,'en','<p>The forum serves as a platform for knowledge exchange, business networking, and strategic discussions that will shape the coal industry''s trajectory for years to come.</p>'),
(20,'en','<p>Tajikistan possesses significant coal reserves estimated at over 4 billion tons, with major deposits located in the Fan-Yagnob, Nazarailok, Shurab, and Ziddi basins.</p>'),
(21,'en','<p>The coal industry plays a vital role in the country''s energy security, particularly during winter months when hydropower generation is limited. The government has identified coal sector development as a strategic priority.</p>'),
(22,'en','<p>With growing energy demands and the need for diversified energy sources, Tajikistan''s coal sector offers substantial opportunities for modernization, investment, and international partnership.</p>'),
(23,'en','Forum Leadership'),
(24,'en','Senior officials guiding the development of the coal industry'),
(25,'en','<p>Engage with one of Central Asia''s most strategic industrial events. Connect with ministers, investors and global mining leaders shaping the next decade of energy and resources in the region.</p>'),
(26,'en','For detailed information on partnership opportunities, please contact the organizing committee.');
INSERT INTO `content_block_values` (`block_id`,`lang`,`value`) VALUES
(1,'ru','25 ноября 2026 — Душанбе'),
(2,'ru','Международный форум угольной промышленности'),
(3,'ru','Таджикистан 2026'),
(4,'ru','Формируя будущее угля Центральной Азии: рост, инновации и устойчивое развитие'),
(5,'ru','Зарегистрироваться'),
(6,'ru','О форуме'),
(7,'ru','<p>Первый в истории Международный форум угольной промышленности в Таджикистане объединяет лидеров отрасли, государственных чиновников, инвесторов и экспертов из Центральной Азии и за её пределами. Форум организован Министерством промышленности и новых технологий Республики Таджикистан.</p>'),
(8,'ru','<p>Мероприятие демонстрирует потенциал угольной отрасли Таджикистана, развивает международное сотрудничество и представляет современные подходы к добыче, экологической устойчивости и инвестиционным возможностям.</p>'),
(9,'ru','Ключевые темы'),
(10,'ru','Шесть основных направлений, формирующих будущее угля Центральной Азии'),
(11,'ru','Партнёры и спонсоры'),
(12,'ru','Организации, поддерживающие развитие угольной отрасли'),
(17,'ru','<p>Международный форум угольной промышленности Таджикистана 2026 — знаковое событие, посвящённое развитию и модернизации угольной отрасли Республики Таджикистан и Центральной Азии в целом.</p>'),
(18,'ru','<p>Впервые в Таджикистане соберутся ведущие эксперты, государственные чиновники, инвесторы, горнодобывающие компании и международные организации для обсуждения текущего состояния и перспектив отрасли в регионе.</p>'),
(19,'ru','<p>Форум станет площадкой для обмена знаниями, делового нетворкинга и стратегических дискуссий, определяющих траекторию развития угольной промышленности на годы вперёд.</p>'),
(20,'ru','<p>Таджикистан располагает значительными запасами угля, оцениваемыми более чем в 4 миллиарда тонн, с крупными месторождениями в бассейнах Фан-Ягноб, Назар-Айлок, Шураб и Зидди.</p>'),
(21,'ru','<p>Угольная отрасль играет важнейшую роль в энергетической безопасности страны, особенно в зимний период, когда выработка гидроэнергии ограничена. Правительство определило развитие угольного сектора как стратегический приоритет.</p>'),
(22,'ru','<p>В условиях растущего спроса на энергию и необходимости диверсификации источников угольный сектор Таджикистана открывает существенные возможности для модернизации, инвестиций и международного партнёрства.</p>'),
(23,'ru','Руководство форума'),
(24,'ru','Высшие должностные лица, определяющие развитие угольной промышленности'),
(25,'ru','<p>Станьте частью одного из самых стратегических промышленных событий Центральной Азии. Встретьтесь с министрами, инвесторами и мировыми лидерами горнодобычи, формирующими следующее десятилетие энергетики и ресурсов региона.</p>'),
(26,'ru','Для получения детальной информации о возможностях партнёрства просьба связаться с оргкомитетом.');
INSERT INTO `content_block_values` (`block_id`,`lang`,`value`) VALUES
(1,'tj','25 ноябри 2026 — Душанбе'),
(2,'tj','Форуми байналмилалии саноати ангишт'),
(3,'tj','Тоҷикистон 2026'),
(4,'tj','Ташаккули ояндаи ангишти Осиёи Марказӣ: рушд, навоварӣ ва пойдории муҳит'),
(5,'tj','Сабти ном'),
(6,'tj','Дар бораи форум'),
(7,'tj','<p>Аввалин Форуми байналмилалии саноати ангишт дар Тоҷикистон пешсафони соҳа, мақомоти давлатӣ, сармоягузорон ва коршиносонро аз Осиёи Марказӣ ва берун аз он муттаҳид мекунад. Форум аз ҷониби Вазорати саноат ва технологияҳои нави Ҷумҳурии Тоҷикистон ташкил карда мешавад.</p>'),
(8,'tj','<p>Чорабинӣ нерӯи саноати ангишти Тоҷикистонро муаррифӣ намуда, ҳамкории байналмилалиро тавсеа медиҳад ва равишҳои муосирро ба истихроҷ, пойдории муҳитӣ ва имкониятҳои сармоягузорӣ пешниҳод мекунад.</p>'),
(9,'tj','Мавзӯъҳои калидӣ'),
(10,'tj','Шаш самти асосие, ки ояндаи ангишти минтақаро ташаккул медиҳанд'),
(11,'tj','Шарикон ва сарпарастон'),
(12,'tj','Созмонҳое, ки рушди саноати ангиштро дастгирӣ мекунанд'),
(17,'tj','<p>Форуми байналмилалии саноати ангишти Тоҷикистон 2026 чорабинии муҳим барои рушд ва навсозии саноати ангишти Ҷумҳурии Тоҷикистон ва Осиёи Марказӣ дар маҷмӯъ мебошад.</p>'),
(18,'tj','<p>Бори аввал дар Тоҷикистон коршиносони пешбар, мақомоти давлатӣ, сармоягузорон, ширкатҳои кӯҳкорӣ ва созмонҳои байналмилалӣ барои муҳокимаи ҳолат ва дурнамои соҳа ҷамъ меоянд.</p>'),
(19,'tj','<p>Форум майдоне барои табодули дониш, шиносоии тиҷоратӣ ва муҳокимаҳои стратегӣ хоҳад буд.</p>'),
(20,'tj','<p>Тоҷикистон захираҳои назарраси ангиштро беш аз 4 миллиард тонна доро мебошад. Конҳои асосӣ дар ҳавзаҳои Фон-Яғноб, Назар-Айлоқ, Шӯроб ва Зидди ҷойгиранд.</p>'),
(21,'tj','<p>Саноати ангишт дар таъмини бехатарии энергетикии кишвар нақши муҳим дорад, бахусус дар фасли зимистон.</p>'),
(22,'tj','<p>Бо афзоиши талабот ба энергия, бахши ангишти Тоҷикистон имкониятҳои васеи навсозӣ, сармоягузорӣ ва шарикии байналмилалиро пешниҳод мекунад.</p>'),
(23,'tj','Роҳбарияти форум'),
(24,'tj','Мақомоти олӣ, ки рушди саноати ангиштро роҳбарӣ мекунанд'),
(25,'tj','<p>Қисми яке аз стратегияҳои муҳимтарини саноатии Осиёи Марказӣ шавед.</p>'),
(26,'tj','Барои маълумоти муфассал дар бораи имкониятҳои шарикӣ бо оргкомитет тамос гиред.');
