INSERT INTO `leadership_translations` (`leadership_id`,`lang`,`full_name`,`position`,`quote`) VALUES
(1,'en','Kokhir Rasulzoda','Prime Minister of the Republic of Tajikistan','The development of the coal industry is a strategic priority for ensuring our country''s energy security and industrial growth.'),
(1,'ru','Кохир Расулзода','Премьер-министр Республики Таджикистан','Развитие угольной промышленности — стратегический приоритет обеспечения энергетической безопасности и промышленного роста нашей страны.'),
(1,'tj','Қоҳир Расулзода','Сарвазири Ҷумҳурии Тоҷикистон','Рушди саноати ангишт самти стратегии таъмини амнияти энергетикӣ ва рушди саноатии кишвари мост.'),
(2,'en','Sherali Kabir','Minister of Industry and New Technologies of the Republic of Tajikistan','The forum opens a new chapter of international cooperation in the coal sector and modernization of mining in Central Asia.'),
(2,'ru','Шерали Кабир','Министр промышленности и новых технологий Республики Таджикистан','Форум открывает новую главу международного сотрудничества в угольном секторе и модернизации горнодобычи в Центральной Азии.'),
(2,'tj','Шералӣ Кабир','Вазири саноат ва технологияҳои нави Ҷумҳурии Тоҷикистон','Форум боби нави ҳамкории байналмилалӣ дар бахши ангишт ва навсозии кӯҳкории Осиёи Марказиро мекушояд.');
