INSERT INTO `news_translations` (`news_id`,`lang`,`title`,`excerpt`,`body`) VALUES
(1,'en','Tajikistan to Host First International Coal Industry Forum in 2026','The Ministry of Industry and New Technologies officially announces the inaugural Coal Industry Forum to be held on November 25, 2026 in Dushanbe.','<p>The Government of Tajikistan, represented by the Ministry of Industry and New Technologies, officially announces the first International Coal Industry Forum to take place on November 25, 2026 at the Kohi Borbad Congress Hall in Dushanbe.</p><p>The forum will gather over 500 delegates from more than 30 countries and aims to position Tajikistan as a strategic hub for the coal industry in Central Asia.</p>'),
(1,'ru','Таджикистан проведёт первый Международный форум угольной промышленности в 2026 году','Министерство промышленности и новых технологий официально объявляет о проведении 25 ноября 2026 года Международного форума угольной промышленности в Душанбе.','<p>Правительство Республики Таджикистан в лице Министерства промышленности и новых технологий официально объявляет о проведении первого Международного форума угольной промышленности 25 ноября 2026 года в Конгресс-холле «Кохи Борбад» в Душанбе.</p><p>На форуме соберутся более 500 делегатов из более чем 30 стран. Цель — позиционирование Таджикистана как стратегического центра угольной промышленности Центральной Азии.</p>'),
(1,'tj','Тоҷикистон Форуми байналмилалии саноати ангиштро дар соли 2026 баргузор мекунад','Вазорати саноат ва технологияҳои нав расман эълон мекунад, ки форум 25 ноябри 2026 дар Душанбе баргузор мегардад.','<p>Ҳукумати Ҷумҳурии Тоҷикистон дар шахси Вазорати саноат ва технологияҳои нав расман эълон мекунад, ки 25 ноябри 2026 Форуми байналмилалии саноати ангишт дар Толори Конгресси «Кохи Борбад»-и Душанбе баргузор мегардад.</p>'),
